import Marquee from "react-fast-marquee";
import { motion } from "framer-motion";

// Google Drive direct image URLs
const galleryImages = [
  { id: 1, src: "https://drive.google.com/uc?export=view&id=1YBx8xQ4tZlZN7h_Ox4FIaZXvLJnGNLM0", alt: "Aperitif" },
  { id: 2, src: "https://drive.google.com/uc?export=view&id=1YGpF8xQ4tZlZN7h_Ox4FIaZXvLJnGNLM0", alt: "Ballentine" },
  { id: 3, src: "https://drive.google.com/uc?export=view&id=1YHpF8xQ4tZlZN7h_Ox4FIaZXvLJnGNLM0", alt: "Bar" },
  { id: 4, src: "https://drive.google.com/uc?export=view&id=1YIpF8xQ4tZlZN7h_Ox4FIaZXvLJnGNLM0", alt: "Bar Night" },
  { id: 5, src: "https://drive.google.com/uc?export=view&id=1YJpF8xQ4tZlZN7h_Ox4FIaZXvLJnGNLM0", alt: "DJ Night" },
  { id: 6, src: "https://drive.google.com/uc?export=view&id=1YKpF8xQ4tZlZN7h_Ox4FIaZXvLJnGNLM0", alt: "Drinks" },
];

// Using placeholder images since Google Drive links need processing
// Using actual images from Corridor Bar's Google Drive
const placeholderImages = [
  { id: 1, src: "/assets/amb.jpg", alt: "Corridor Ambience", type: "image" },
  { id: 2, src: "/assets/apr.jpg", alt: "Aperitif", type: "image" },
  { id: 3, src: "/assets/ballent.jpg", alt: "Ballentine", type: "image" },
  { id: 4, src: "/assets/bl.jpg", alt: "Bar Lounge", type: "image" },
  { id: 5, src: "/assets/bn.jpg", alt: "Bar Night", type: "image" },
  { id: 6, src: "/assets/dj.jpg", alt: "DJ Night", type: "image" },
  { id: 7, src: "/assets/dri.jpg", alt: "Drinks", type: "image" },
  { id: 8, src: "/assets/f1.jpg", alt: "Food", type: "image" },
  { id: 9, src: "/assets/grp.jpg", alt: "Group Party", type: "image" },
  { id: 10, src: "/assets/nod.jpg", alt: "Night Out", type: "image" },
  { id: 11, src: "/assets/pic.jpg", alt: "Corridor Vibes", type: "image" },
  { id: 12, src: "/assets/piz.jpg", alt: "Pizza", type: "image" },
  { id: 13, src: "/assets/corridor-video.mp4", alt: "Corridor Video", type: "video" },
];

const MovingGallery = () => {
  return (
    <section data-testid="moving-gallery" className="py-16 md:py-24 overflow-hidden bg-black">
      <motion.div
        initial={{ opacity: 0 }}
        whileInView={{ opacity: 1 }}
        transition={{ duration: 0.8 }}
        viewport={{ once: true }}
        className="mb-12 text-center"
      >
        <span className="font-accent text-gold text-sm tracking-[0.3em] uppercase">Experience</span>
        <h2 className="font-heading text-4xl md:text-5xl text-white mt-2">The Vibe</h2>
      </motion.div>

      {/* First row - left to right */}
      <div className="mb-6">
        <Marquee speed={40} gradient={false} pauseOnHover>
          {placeholderImages.map((image) => (
            <div
              key={image.id}
              className="mx-3 relative overflow-hidden group"
            >
              <div className="w-[300px] md:w-[400px] h-[200px] md:h-[280px] overflow-hidden">
                <img
                  src={image.src}
                  alt={image.alt}
                  className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-500 group-hover:scale-110"
                  onLoad={(e) => e.target.style.opacity = 1}
                  style={{ opacity: 1 }}
                />
              </div>
              <div className="absolute inset-0 border border-gold/0 group-hover:border-gold/50 transition-all duration-300" />
            </div>
          ))}
        </Marquee>
      </div>

      {/* Second row - right to left */}
      <div>
        <Marquee speed={40} direction="right" gradient={false} pauseOnHover>
          {[...placeholderImages].reverse().map((image) => (
            <div
              key={`rev-${image.id}`}
              className="mx-3 relative overflow-hidden group"
            >
              <div className="w-[300px] md:w-[400px] h-[200px] md:h-[280px] overflow-hidden">
                <img
                  src={image.src}
                  alt={image.alt}
                  className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-500 group-hover:scale-110"
                  onLoad={(e) => e.target.style.opacity = 1}
                  style={{ opacity: 1 }}
                />
              </div>
              <div className="absolute inset-0 border border-gold/0 group-hover:border-gold/50 transition-all duration-300" />
            </div>
          ))}
        </Marquee>
      </div>
    </section>
  );
};

export default MovingGallery;
